import React, { useState, useRef, useEffect } from 'react';
import { NavLink } from 'react-router-dom';
import { MoonIcon, SunIcon, MenuIcon, ChevronDownIcon } from './Icons';

export default function Topbar({ title, username, theme, onMenuClick, onToggleTheme, onLogout }) {
  const [userDropdownOpen, setUserDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setUserDropdownOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <header className="topbar">
      <div className="topbar-left">
        <button className="menu-toggle" type="button" onClick={onMenuClick} aria-label="Open navigation">
          <MenuIcon className="w-5 h-5" />
        </button>
        <div className="topbar-info">
          <p className="topbar-label">Welcome back</p>
          <h2 className="topbar-title">{title}</h2>
        </div>
      </div>

      <div className="topbar-actions">
        <button className="theme-button" type="button" onClick={onToggleTheme} aria-label="Toggle theme">
          {theme === 'light' ? <MoonIcon className="w-5 h-5" /> : <SunIcon className="w-5 h-5" />}
        </button>
        <div className="user-dropdown" ref={dropdownRef}>
          <button
            className="topbar-user"
            type="button"
            onClick={() => setUserDropdownOpen(!userDropdownOpen)}
            aria-label="User menu"
          >
            <span className="user-avatar">{username?.charAt(0).toUpperCase()}</span>
            <span className="user-name">{username}</span>
            <ChevronDownIcon className="w-4 h-4" />
          </button>
          {userDropdownOpen && (
            <div className="user-dropdown-menu">
              <button
                className="user-dropdown-item"
                type="button"
                onClick={() => {
                  setUserDropdownOpen(false);
                  onLogout();
                }}
              >
                Logout
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
